import { css } from '@emotion/core';
import { colors } from 'core';

export const popoverListContent = css`
  background-color: ${colors.variants.Background.Primary};
  border-radius: 4px;
  box-shadow: 0px 1px 12px rgba(0, 0, 0, 0.08);
`;
